BeforeAll {
    $script:ModuleRoot = Split-Path -Parent $MyInvocation.MyCommand.Path
    $script:ScriptPath = Join-Path $ModuleRoot "DependencyLicenseChecker.ps1"
}

Describe "DependencyLicenseChecker" {
    BeforeEach {
        # Clean up any test artifacts
        $script:MockLicenses = @{}
